//#region src/services/timeMeterDiscount.ts
function calculateTimeMeterDiscountRates(legalSettings, initialMinutes, additionalSeconds) {
	const { baseFareYen, baseMinutes } = legalSettings;
	if (baseMinutes <= 0) return {
		initialFareYen: 0,
		additionalFareYen: 0
	};
	const ratePerMinute = baseFareYen / baseMinutes;
	return {
		initialFareYen: Math.floor(ratePerMinute * initialMinutes),
		additionalFareYen: Math.floor(ratePerMinute * (additionalSeconds / 60))
	};
}
//#endregion
//#region src/services/timeMeterFare.ts
function calculateUnitIncreaseProgress(elapsedSeconds, unitSeconds) {
	if (elapsedSeconds <= 0 || unitSeconds <= 0) return {
		elapsedSeconds: 0,
		progressRate: 0,
		remainingSeconds: unitSeconds,
		unitSeconds
	};
	const secondsIntoCurrentUnit = elapsedSeconds % unitSeconds;
	const remainingSeconds = secondsIntoCurrentUnit === 0 ? unitSeconds : unitSeconds - secondsIntoCurrentUnit;
	return {
		elapsedSeconds: secondsIntoCurrentUnit,
		progressRate: Math.min(secondsIntoCurrentUnit / unitSeconds, 1),
		remainingSeconds,
		unitSeconds
	};
}
function calculateTimeMeterFareIncreaseProgress(elapsedSeconds, discountSettings, legalSettings) {
	const initialThresholdSeconds = discountSettings.enabled ? discountSettings.initialMinutes * 60 : legalSettings.baseMinutes * 60;
	const additionalUnitSeconds = discountSettings.enabled ? discountSettings.additionalSeconds : legalSettings.additionalMinutes * 60;
	if (elapsedSeconds <= initialThresholdSeconds) {
		const elapsedIntoInitial = Math.max(elapsedSeconds, 0);
		const remainingSeconds = Math.max(initialThresholdSeconds - elapsedIntoInitial, 0);
		return {
			elapsedSeconds: elapsedIntoInitial,
			label: "初回時間まで",
			progressRate: initialThresholdSeconds > 0 ? Math.min(elapsedIntoInitial / initialThresholdSeconds, 1) : 0,
			remainingSeconds,
			unitSeconds: initialThresholdSeconds
		};
	}
	return {
		label: "時間加算まで",
		...calculateUnitIncreaseProgress(elapsedSeconds - initialThresholdSeconds, additionalUnitSeconds)
	};
}
function formatTimeMeterFareIncreaseProgressLabel(progress) {
	const formatDuration = (totalSeconds) => {
		const normalizedSeconds = Math.max(Math.floor(totalSeconds), 0);
		if (normalizedSeconds >= 60) return `${Math.floor(normalizedSeconds / 60)}分 ${normalizedSeconds % 60}秒`;
		return `${normalizedSeconds}秒`;
	};
	return `${formatDuration(progress.elapsedSeconds)} / ${formatDuration(progress.unitSeconds)}`;
}
function calculateLegalTimeFareYen(elapsedSeconds, legalSettings) {
	const { baseFareYen, baseMinutes, additionalMinutes, additionalFareYen } = legalSettings;
	if (elapsedSeconds <= 0) return 0;
	const elapsedMinutes = elapsedSeconds / 60;
	return baseFareYen + (additionalMinutes > 0 ? Math.ceil(Math.max(0, elapsedMinutes - baseMinutes) / additionalMinutes) : 0) * additionalFareYen;
}
function calculateActualTimeFareYen({ elapsedSeconds, discountSettings, legalSettings }) {
	if (!discountSettings.enabled) return calculateLegalTimeFareYen(elapsedSeconds, legalSettings);
	const { initialMinutes, additionalSeconds } = discountSettings;
	const { initialFareYen, additionalFareYen } = calculateTimeMeterDiscountRates(legalSettings, initialMinutes, additionalSeconds);
	const initialThresholdSeconds = initialMinutes * 60;
	if (elapsedSeconds <= initialThresholdSeconds) return initialFareYen;
	return initialFareYen + Math.ceil((elapsedSeconds - initialThresholdSeconds) / additionalSeconds) * additionalFareYen;
}
function calculateTimeMeterFare({ elapsedSeconds, discountSettings, legalSettings }) {
	const legalTimeFare = calculateLegalTimeFareYen(elapsedSeconds, legalSettings);
	const actualTimeFare = calculateActualTimeFareYen({
		elapsedSeconds,
		discountSettings,
		legalSettings
	});
	return {
		actualTimeFare,
		legalTimeFare,
		timeDiscountAmount: discountSettings.enabled ? Math.max(0, legalTimeFare - actualTimeFare) : 0,
		timeDiscountEnabled: discountSettings.enabled,
		initialMinutes: discountSettings.initialMinutes,
		additionalSeconds: discountSettings.additionalSeconds
	};
}
