			specialVehicleFareYen,
			basicFareYen,
			waitingFareYen,
			meterTimeFareYen: 0,
			escortFareYen,
			careOptionFareYen,
			expenseFareYen,
			grossFareYen,
			discountableFareYen,
			isDisabilityDiscount,
			disabilityDiscountRate: discountRate,
			disabilityDiscountAmount,
			discountName,
			discountMethod: discountSettings.method,
			discountValue,
