	const disabilityDiscountAmount = isDisabilityDiscount ? Math.min(discountSettings.method === "percentage" ? roundDownToTenYen(discountableFareYen * discountRate) : Math.round(discountValue), discountableFareYen) : 0;
	const discountedMeterFareYen = Math.max(discountableFareYen - disabilityDiscountAmount, 0);
	const taxiTicketRequestedYen = taxiTickets.reduce((total, ticket) => total + Math.max(Math.round(ticket.amount) || 0, 0), 0);
	const taxiTicketAmountYen = Math.min(taxiTicketRequestedYen, discountedMeterFareYen);
