function formatTimerClock(totalSeconds, includesHours = false) {
	const normalizedSeconds = Math.max(Math.floor(totalSeconds), 0);
	const hours = Math.floor(normalizedSeconds / 3600);
	const minutes = Math.floor(normalizedSeconds % 3600 / 60);
	const seconds = normalizedSeconds % 60;
	return includesHours ? `${formatClockSegment(hours)}:${formatClockSegment(minutes)}:${formatClockSegment(seconds)}` : `${formatClockSegment(minutes + hours * 60)}:${formatClockSegment(seconds)}`;
}
